import{_ as d,c as r,a,o as e}from"./app-CEcM0piI.js";const h={};function n(c,t){return e(),r("div",null,t[0]||(t[0]=[a('<h3 id="算数运算符" tabindex="-1"><a class="header-anchor" href="#算数运算符"><span>算数运算符</span></a></h3><table><thead><tr><th>运算符</th><th>含义</th></tr></thead><tbody><tr><td>+</td><td>加</td></tr><tr><td>-</td><td>减</td></tr><tr><td>*</td><td>乘</td></tr><tr><td>/</td><td>除（有余数）</td></tr><tr><td>//</td><td>整数除（没有余数，向下取整）</td></tr><tr><td>%</td><td>余数，模运算（取两数相除的余数）</td></tr><tr><td>+</td><td>正号</td></tr><tr><td>-</td><td>负号</td></tr><tr><td>**</td><td>幂运算</td></tr><tr><td>=</td><td>赋值运算符</td></tr><tr><td>优先级：（）&gt;右结合&gt;左结合</td><td></td></tr></tbody></table><p>给一个三位数，求取它的百位/十位/个位: 百位//100 十位//10%10 个位%10</p><p>简化运算</p><table><thead><tr><th>运算符</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td>+=</td><td>加法赋值运算符</td><td>c+=a等效于c=c+a</td></tr><tr><td>-=</td><td>减法赋值运算符</td><td>c-=a等效于c=c-a</td></tr><tr><td>*=</td><td>乘法赋值运算符</td><td>c*=a等效于c=c*a</td></tr><tr><td>/=</td><td>除法赋值运算符</td><td>c/=a等效于c=c/a<br></td></tr><tr><td>%=</td><td>取模赋值运算符</td><td>c%=a等效于c=c/a</td></tr><tr><td>**=</td><td>幂赋值运算符</td><td>c**=a等效于c=c**a</td></tr><tr><td>//=</td><td>取整除赋值运算符</td><td>c//=a等效于c=c//a</td></tr></tbody></table><h3 id="变量和赋值运算" tabindex="-1"><a class="header-anchor" href="#变量和赋值运算"><span>变量和赋值运算</span></a></h3><p>变量：计算机中储存信息的一部分内存，它可以储存所有可以变化的值</p><p>可以使用数字、字母、下划线</p><p>首字符不可以是数字</p><p>不能使用python中的关键字</p><p>赋值运算符是=。赋值运算要求运算符的左侧一定是一个变量，运算符的右侧可以是常数、变量，也可以是一个表达式</p><h3 id="比较运算符" tabindex="-1"><a class="header-anchor" href="#比较运算符"><span>比较运算符</span></a></h3><table><thead><tr><th>运算符</th><th>含义</th></tr></thead><tbody><tr><td>==</td><td>相等值比较</td></tr><tr><td>!=</td><td>不等值比较</td></tr><tr><td>&lt;</td><td>小于比较</td></tr><tr><td>&gt;</td><td>大于比较</td></tr><tr><td>&gt;=</td><td>大于等于比较</td></tr><tr><td>&lt;=</td><td>小于等于比较</td></tr></tbody></table><h3 id="逻辑运算" tabindex="-1"><a class="header-anchor" href="#逻辑运算"><span>逻辑运算</span></a></h3><table><thead><tr><th>运算符</th><th>含义</th></tr></thead><tbody><tr><td>and</td><td>两个为真才是真</td></tr><tr><td>or</td><td>只需一个为真是真，两个为假才是假</td></tr><tr><td>not</td><td>真假变换</td></tr></tbody></table><p>逻辑运算符优先级: ()&gt;not&gt;and&gt;or</p>',16)]))}const p=d(h,[["render",n]]),s=JSON.parse('{"path":"/python/python/2/","title":"2 运算符","lang":"zh-CN","frontmatter":{"title":"2 运算符","createTime":"2025/04/05 12:12:26","permalink":"/python/python/2/"},"readingTime":{"minutes":1.41,"words":422},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/Python/python/2 运算符.md","headers":[]}');export{p as comp,s as data};
